// NQxb_Artifact_Update_v1__Normalize_Request
// UPDATE-ONLY: Require artifact_id, reject if missing
// v2: Tags forwarding (T41 — Mutability Registry v2)
// T94: Twig lifecycle_status support
// T140: Content field extraction (content, content_append, content_mode)

const raw = $json ?? {};

const body =
  raw.body && typeof raw.body === "object" && !Array.isArray(raw.body)
    ? raw.body
    : null;

const req = body ?? raw;

const asObj = (v) =>
  v && typeof v === "object" && !Array.isArray(v) ? v : {};

const artifact_id = req.artifact_id ?? null;
const artifact_type = (req.artifact_type ?? "").trim();

// UPDATE_ONLY: artifact_id is REQUIRED
if (!artifact_id || artifact_id.trim() === '') {
  return [
    {
      json: {
        ok: false,
        _gw_route: "error",
        error: {
          code: "UPDATE_ONLY",
          message: "artifact.update is update-only. Use artifact.create for new artifacts.",
          details: {
            hint: "artifact_id field is required for UPDATE operations."
          },
        },
      },
    },
  ];
}

// Tags canonicalization (Mutability Registry v2 — spine-level, type-agnostic)
const rawTags = req.tags ?? null;
let tags = null;
if (rawTags && typeof rawTags === 'object' && !Array.isArray(rawTags)) {
  const addArr = Array.isArray(rawTags.add) ? rawTags.add : [];
  const removeArr = Array.isArray(rawTags.remove) ? rawTags.remove : [];
  const addSet = [...new Set(addArr.filter(t => typeof t === 'string' && t.trim().length > 0).map(t => t.trim()))];
  const removeSet = [...new Set(removeArr.filter(t => typeof t === 'string' && t.trim().length > 0).map(t => t.trim()))];
  if (addSet.length > 0 || removeSet.length > 0) {
    tags = { add: addSet, remove: removeSet };
  }
}

// T87: Spine fields extraction
const spine_fields = {};

if ('title' in req) spine_fields.title = req.title;
if ('summary' in req) spine_fields.summary = req.summary;
if ('priority' in req) spine_fields.priority = req.priority;
if ('parent_artifact_id' in req) spine_fields.parent_artifact_id = req.parent_artifact_id;

// T94: lifecycle_status extraction (twig-only)
// Twig lifecycle transitions go through artifact.update, not artifact.promote.
// Guard: Check_Mutability_Rules v9 blocks lifecycle_status for non-twig types.
if ('lifecycle_status' in req && artifact_type === 'twig') {
  spine_fields.lifecycle_status = req.lifecycle_status;
}


// T140: Content field extraction
// content = JSON object for mutable-type merge/replace updates
// content_append = JSON object for immutable-type append-only updates
// content_mode = 'merge' (default) or 'replace' — controls content update semantics
const rawContent = req.content ?? null;
const content = (rawContent && typeof rawContent === 'object' && !Array.isArray(rawContent))
  ? rawContent : null;

const rawContentAppend = req.content_append ?? null;
const content_append = (rawContentAppend && typeof rawContentAppend === 'object' && !Array.isArray(rawContentAppend))
  ? rawContentAppend : null;

const content_mode = (typeof req.content_mode === 'string' && req.content_mode.trim().length > 0)
  ? req.content_mode.trim() : null;

// T140 B4 L2: Content shape validation flag
// Detect if content was provided but is not a valid object (array or primitive)
const _content_raw_invalid = rawContent !== null && rawContent !== undefined
  && (typeof rawContent !== 'object' || Array.isArray(rawContent));

// recompute after all spine fields added
const hasSpineFields = Object.keys(spine_fields).length > 0;

const canonical = {
  gw_action: req.gw_action ?? "artifact.update",
  gw_workspace_id: req.gw_workspace_id ?? null,
  artifact_type: artifact_type,
  artifact_id: artifact_id.trim(),

  // Extension fields (only operational_state and state_reason allowed for project)
  extension: asObj(req.extension),

  // Tags
  tags: tags,

  // Spine fields
  spine_fields: hasSpineFields ? spine_fields : null,

  // T140: Content fields
  content: content,
  content_append: content_append,
  content_mode: content_mode,
  _content_raw_invalid: _content_raw_invalid,

  // deleted_at (BLOCKED - UNDECIDED per Mutability Registry v1)
  deleted_at: req.deleted_at ?? null,
};

canonical._gw_debug = {
  received_shape: body ? "body" : "flat",
  operation: "UPDATE",
  has_tags: tags !== null,
  has_extension: Object.keys(canonical.extension).length > 0,
  has_spine_fields: hasSpineFields,
  spine_field_keys: hasSpineFields ? Object.keys(spine_fields) : [],
  has_content: content !== null,
  has_content_append: content_append !== null,
  has_content_mode: content_mode !== null,
  content_raw_invalid: _content_raw_invalid,
};

return [{ json: canonical }];

// NQxb_Artifact_Update_v1__Validate_Request
// UPDATE-only validation (strict, predictable, preserves payload)
// v3.0: Extension optional when tags present (T41)
// v4.0: T140
// v5.0: T140 B4 — CONTENT_INVALID_SHAPE rejection — Content mode conflict validation

const req = $json ?? {};
const errors = [];

function isNonEmptyString(v) {
  return typeof v === "string" && v.trim().length > 0;
}

function asObj(v) {
  return v && typeof v === "object" && !Array.isArray(v) ? v : {};
}

// Required: gw_workspace_id
if (!isNonEmptyString(req.gw_workspace_id)) {
  errors.push({ field: "gw_workspace_id", reason: "required", expected: "uuid string" });
}

// Required: artifact_type
if (!isNonEmptyString(req.artifact_type)) {
  errors.push({ field: "artifact_type", reason: "required", expected: "non-empty string" });
}

// Required: artifact_id
if (!isNonEmptyString(req.artifact_id)) {
  errors.push({ field: "artifact_id", reason: "required", expected: "uuid string" });
}

// Extension validation: optional when tags present, but if present must be object
const hasExtension = req.extension && typeof req.extension === "object" && !Array.isArray(req.extension);
const hasTags = req.tags !== null && req.tags !== undefined;

if (req.extension !== undefined && req.extension !== null && !hasExtension) {
  // Extension was provided but is not a valid object
  errors.push({ field: "extension", reason: "invalid_type", expected: "object (if provided)" });
}

const hasSpineFields = req.spine_fields !== null && req.spine_fields !== undefined && Object.keys(req.spine_fields).length > 0;

// T140 B4 L2: Content shape validation — reject arrays and primitives
if (req._content_raw_invalid) {
  errors.push({ field: "content", reason: "must be a JSON object (not array or primitive)", expected: "object", code: "CONTENT_INVALID_SHAPE" });
}

// T140: Content mode conflict validation (L5)
const hasContent = req.content !== null && req.content !== undefined;
const hasContentAppend = req.content_append !== null && req.content_append !== undefined;

if (hasContent && hasContentAppend) {
  errors.push({ field: "content_mode_conflict", reason: "Cannot provide both content and content_append in the same request", expected: "one of: content OR content_append" });
}

if (hasContentAppend && hasTags) {
  errors.push({ field: "content_mode_conflict", reason: "Cannot combine content_append with tags update", expected: "content_append must be submitted alone" });
}

const hasExtensionKeys = hasExtension && Object.keys(asObj(req.extension)).length > 0;
if (hasContentAppend && (hasExtensionKeys || hasSpineFields)) {
  errors.push({ field: "content_mode_conflict", reason: "Cannot combine content_append with extension or spine field updates", expected: "content_append must be submitted alone" });
}

if (!hasExtension && !hasTags && !hasSpineFields && !hasContent && !hasContentAppend) {
  errors.push({ field: "update_fields", reason: "required", expected: "at least one of: extension, tags, spine_fields, content, or content_append" });
}

const ext = hasExtension ? asObj(req.extension) : {};

if (errors.length > 0) {
  return [
    {
      json: {
        ok: false,
        _gw_route: "error",
        error: {
          code: "VALIDATION_ERROR",
          message: "Validation failed for artifact.update (UPDATE)",
          details: {
            validation_errors: errors,
            operation: "UPDATE",
            artifact_type: req.artifact_type ?? null,
            artifact_id: req.artifact_id ?? null,
          },
        },
        gw_action: req.gw_action ?? "artifact.update",
        gw_workspace_id: req.gw_workspace_id ?? null,
        artifact_type: req.artifact_type ?? null,
        artifact_id: req.artifact_id ?? null,
        _gw_debug: req._gw_debug ?? undefined,
      },
    },
  ];
}

// Pass-through with normalized values
return [
  {
    json: {
      ...req,
      ok: true,
      _gw_route: "ok",
      gw_action: req.gw_action ?? "artifact.update",
      extension: ext,
      tags: req.tags ?? null,
      deleted_at: req.deleted_at ?? null,
      _gw_debug: {
        ...(req._gw_debug ?? {}),
        operation: "UPDATE",
        received_shape: (req._gw_debug && req._gw_debug.received_shape) ? req._gw_debug.received_shape : "flat",
      },
    },
  },
];

// Type Registry Guard
// Check artifact type against qxb_artifact_type_registry
// Error code: ARTIFACT_TYPE_NOT_ALLOWED
// Fail-closed: no row or disabled = reject

// Get original request from the Guard_Error_ShortCircuit node (ok path)
const originalRequest = $node['NQxb_Artifact_Update_v1__Guard_Error_ShortCircuit'].json;

// Get registry lookup result (may be empty if no row found)
const registryRow = $json;

const artifact_type = originalRequest.artifact_type;

// FAIL-CLOSED: No row found = type not registered
if (!registryRow || !registryRow.artifact_type) {
  return [{
    json: {
      ok: false,
      _gw_route: 'error',
      gw_action: originalRequest.gw_action ?? 'artifact.update',
      gw_workspace_id: originalRequest.gw_workspace_id ?? null,
      artifact_type: artifact_type,
      artifact_id: originalRequest.artifact_id ?? null,
      error: {
        code: 'ARTIFACT_TYPE_NOT_ALLOWED',
        message: `Artifact type '${artifact_type}' is not allowed`,
        details: {
          artifact_type: artifact_type,
          reason: 'not_registered',
          hint: 'Type must be registered in qxb_artifact_type_registry'
        }
      },
      timestamp: new Date().toISOString()
    }
  }];
}

// Type found but disabled
if (registryRow.enabled === false) {
  return [{
    json: {
      ok: false,
      _gw_route: 'error',
      gw_action: originalRequest.gw_action ?? 'artifact.update',
      gw_workspace_id: originalRequest.gw_workspace_id ?? null,
      artifact_type: artifact_type,
      artifact_id: originalRequest.artifact_id ?? null,
      error: {
        code: 'ARTIFACT_TYPE_NOT_ALLOWED',
        message: `Artifact type '${artifact_type}' is not allowed`,
        details: {
          artifact_type: artifact_type,
          reason: 'disabled',
          registry_enabled: false,
          hint: 'Type is registered but currently disabled'
        }
      },
      timestamp: new Date().toISOString()
    }
  }];
}

// Type is registered and enabled - pass through original request
return [{ json: originalRequest }];

// NQxb_Artifact_Update_v1__Check_Mutability_Rules
// Enforce Mutability Registry v3 rules
// v3: T64
// v4: T71 â€” dependency check flagging for leaf completing â€” spine-field update mode for branch/limb/leaf
// v5: T69 architectural fix
// v6: T87 -- Spine field routing (title, summary, priority) + mixed update support
// v7: T87 Task 3 -- Lifecycle-scoped mutability governance
// v8: T87 Task 4 -- design_spine added to project extension allowlist
// v9: T94 -- twig added
// v10: T140 -- content mode detection
// v11: T140 B4 -- archive freeze for content updates (all types) (content_update, content_append) before mutability to execution anatomy types (no extension table, lifecycle via spine)
//   - archive: ALL mutations blocked (spine, extension, tags)
//   - tree: title frozen (summary, priority, extension, tags remain mutable)
//   - seed/sapling: fully mutable
//
// Order of checks:
// 1. Existence check (NOT_FOUND)
// 2. Lifecycle-scoped archive guard (blocks everything)
// 3. Routing classification (T87)
//    Three dimensions: hasTags, hasSpineFields, hasExtension
// 4. Lifecycle-scoped tree guard (title frozen -- checked in spine/mixed paths)
// 5. Type-specific rules

const existing = $json;
const artifact_type = existing.artifact_type;
const lifecycle_status = existing.lifecycle_status ?? null;

// Pull the normalized request from the Normalize_Request node output.
function getNormalizeNode() {
  const candidateNodeNames = [
    "NQxb_Artifact_Update_v1__Normalize_Request",
    "Normalize_Request",
    "NQxb_Artifact_Update_v1__Normalize_Request_v3",
  ];

  for (const name of candidateNodeNames) {
    try {
      const items = $items(name, 0);
      if (items && items.length > 0 && items[0]?.json) return items[0].json;
    } catch (e) {
      // ignore and try next name
    }
  }

  if (existing._normalized_request) return existing._normalized_request;
  if (existing.normalizeNode) return existing.normalizeNode;

  return {};
}

const normalizeNode = getNormalizeNode();

const normalizedTags = normalizeNode.tags ?? null;
const extensionKeys = Object.keys(normalizeNode.extension || {});
// T87: Spine field detection â€” check both normalizeNode.spine_fields AND $json top-level
// Belt-and-suspenders: works regardless of which upstream node provides the data
const spineFieldsObj = normalizeNode.spine_fields || {};
const spineFieldKeys = Object.keys(spineFieldsObj);

const hasSpineFields = spineFieldKeys.length > 0;

const hasTags = normalizedTags !== null;
const hasExtension = extensionKeys.length > 0;

// T140: Content dimension detection (L1 — before mutability checks)
const hasContent = normalizeNode.content !== null && normalizeNode.content !== undefined;
const hasContentAppend = normalizeNode.content_append !== null && normalizeNode.content_append !== undefined;



// ============================================================================
// T140 L1: CONTENT MODE DETECTION (before mutability checks)
// content_append → stub (B3 will implement lifecycle enforcement)
// content_update → route through Compute_Mixed path
// ============================================================================

// T140: content_append mode — route to stub (B3/B4 will implement)
if (hasContentAppend && !hasTags && !hasSpineFields && !hasExtension && !hasContent) {
  return [{
    json: {
      ok: true,
      _gw_route: 'ok',
      _update_mode: 'content_append',
      gw_action: normalizeNode.gw_action ?? 'artifact.update',
      gw_workspace_id: normalizeNode.gw_workspace_id ?? null,
      artifact_id: existing.artifact_id,
      workspace_id: existing.workspace_id,
      artifact_type: artifact_type,
      _normalized_request: normalizeNode,
      _existing_artifact: existing,
      _gw_debug: {
        ...(normalizeNode._gw_debug ?? {}),
        mutability: 'content_append_detected',
        operation: 'UPDATE',
      },
    },
  }];
}

// T140: content_update mode — block immutable types (must use content_append)
if (hasContent) {
  const immutableContentTypes = ['snapshot', 'restart', 'journal', 'instruction_pack'];
  if (immutableContentTypes.includes(artifact_type)) {
    return [{
      json: {
        ok: false,
        _gw_route: 'error',
        error: {
          code: 'CONTENT_UPDATE_NOT_ALLOWED',
          message: "Content updates via merge/replace are not allowed for immutable type '" + artifact_type + "'. Use content_append instead.",
          details: {
            artifact_id: existing.artifact_id,
            artifact_type: artifact_type,
            hint: 'Immutable artifact types (snapshot, restart, journal, instruction_pack) only support content_append operations.',
          },
        },
      },
    }];
  }
}

// ============================================================================
// T140 B4 L1: Archive freeze for content updates (ALL types, not just project)
// Any artifact with lifecycle_status = 'archive' is fully frozen.
// ============================================================================
if (hasContent && lifecycle_status === 'archive') {
  return [{
    json: {
      ok: false,
      _gw_route: 'error',
      error: {
        code: 'ARCHIVE_FROZEN',
        message: "Archived artifacts are fully immutable. Content updates are not permitted.",
        details: {
          artifact_id: existing.artifact_id,
          artifact_type: artifact_type,
          lifecycle_status: 'archive',
          operation: 'content_update',
          hint: 'Archived artifacts are read-only historical records. No content mutations are allowed.',
        },
      },
    },
  }];
}

// ============================================================================
// 1.5 LIFECYCLE GUARD: archive = ALL mutations blocked
// Applies to projects only (execution anatomy has its own archive guard at 6.7.5)
// ============================================================================
if (artifact_type === "project" && lifecycle_status === "archive") {
  const attemptedFields = [];
  if (hasSpineFields) attemptedFields.push(...spineFieldKeys.map(k => `spine.${k}`));
  if (hasExtension) attemptedFields.push(...extensionKeys.map(k => `extension.${k}`));
  if (hasTags) attemptedFields.push("tags");

  return [
    {
      json: {
        ok: false,
        _gw_route: "error",
        error: {
          code: "ARCHIVE_IMMUTABLE",
          message: "Archived projects are fully immutable. No mutations are permitted.",
          details: {
            artifact_id: existing.artifact_id,
            artifact_type: "project",
            lifecycle_status: "archive",
            attempted_fields: attemptedFields,
            hint: "Archived artifacts are read-only historical records. No spine, extension, or tag updates are allowed.",
          },
        },
      },
    },
  ];
}


// 2d. Extension + (tags OR spine fields) = MIXED_UPDATE_NOT_ALLOWED
if (hasExtension && (hasTags || hasSpineFields)) {
  return [
    {
      json: {
        ok: false,
        _gw_route: "error",
        error: {
          code: "MIXED_UPDATE_NOT_ALLOWED",
          message: "Cannot combine extension fields with tags or spine fields in a single update. Send extension updates separately.",
          details: {
            artifact_id: existing.artifact_id,
            artifact_type: artifact_type,
            has_extension: true,
            has_tags: hasTags,
            has_spine_fields: hasSpineFields,
            spine_field_keys: spineFieldKeys,
            hint: "Split into two requests: (1) extension-only update, (2) tags/spine update.",
          },
        },
      },
    },
  ];
}

// ============================================================================
// LIFECYCLE GUARD HELPER: tree = title frozen
// Used by spine_only and mixed paths below
// ============================================================================
function checkTreeTitleFreeze() {
  if (artifact_type === "project" && lifecycle_status === "tree" && spineFieldKeys.includes("title")) {
    return {
      ok: false,
      _gw_route: "error",
      error: {
        code: "FIELD_FROZEN",
        message: "Field 'title' is frozen at lifecycle stage 'tree'. Title cannot be changed once a project reaches tree.",
        details: {
          artifact_id: existing.artifact_id,
          artifact_type: "project",
          lifecycle_status: "tree",
          frozen_field: "title",
          allowed_spine_fields: spineFieldKeys.filter(k => k !== "title"),
          hint: "At tree stage, title is locked as the project's permanent identity. Summary and priority remain mutable.",
        },
      },
    };
  }
  return null;
}

// 2a. Tags only (T140: exclude content modes)
if (hasTags && !hasSpineFields && !hasExtension && !hasContent && !hasContentAppend) {
  return [
    {
      json: {
        ok: true,
        _gw_route: "ok",
        _update_mode: "tags_only",
        gw_action: normalizeNode.gw_action ?? "artifact.update",
        gw_workspace_id: normalizeNode.gw_workspace_id ?? null,
        artifact_id: existing.artifact_id,
        workspace_id: existing.workspace_id,
        artifact_type: artifact_type,
        _normalized_request: normalizeNode,
        _existing_artifact: existing,
        _gw_debug: {
          ...(normalizeNode._gw_debug ?? {}),
          mutability: "tags_only_bypass",
          operation: "UPDATE",
        },
      },
    },
  ];
}

// 2a.5 GUARD: lifecycle_status via spine_fields is TWIG-ONLY
// Projects use artifact.promote -- direct lifecycle_status update is blocked.
if (hasSpineFields && spineFieldKeys.includes('lifecycle_status') && artifact_type !== 'twig') {
  return [
    {
      json: {
        ok: false,
        _gw_route: 'error',
        error: {
          code: 'MUTABILITY_ERROR',
          message: "Field 'lifecycle_status' cannot be updated via artifact.update for type '" + artifact_type + "'. Use artifact.promote for lifecycle transitions.",
          details: {
            field: 'lifecycle_status',
            artifact_type: artifact_type,
            artifact_id: existing.artifact_id,
            registry_rule: 'PROMOTE_ONLY',
            hint: 'lifecycle_status updates via spine fields are only allowed for twig artifacts. Projects must use artifact.promote.',
          },
        },
      },
    },
  ];
}

// 2a.6 GUARD: twig lifecycle transition validation
if (hasSpineFields && spineFieldKeys.includes('lifecycle_status') && artifact_type === 'twig') {
  const currentLifecycle = existing.lifecycle_status ?? null;
  const requestedLifecycle = spineFieldsObj.lifecycle_status ?? null;

  // Terminal states: promoted and pruned cannot be changed
  if (currentLifecycle === 'promoted' || currentLifecycle === 'pruned') {
    return [
      {
        json: {
          ok: false,
          _gw_route: 'error',
          error: {
            code: 'ARCHIVE_TERMINAL',
            message: 'Cannot update lifecycle_status on ' + currentLifecycle + ' twig. Terminal state.',
            details: {
              artifact_id: existing.artifact_id,
              artifact_type: 'twig',
              lifecycle_status: currentLifecycle,
              hint: 'Twigs in promoted or pruned state are terminal. Archive the twig and create a new artifact if needed.',
            },
          },
        },
      },
    ];
  }

  // Transition matrix: proposed -> active -> promoted | pruned
  const twigTransitions = {
    'null': ['proposed'],
    'proposed': ['active', 'pruned'],
    'active': ['promoted', 'pruned'],
  };

  const fromKey = currentLifecycle === null ? 'null' : currentLifecycle;
  const allowed = twigTransitions[fromKey] || [];

  if (requestedLifecycle !== null && !allowed.includes(requestedLifecycle)) {
    return [
      {
        json: {
          ok: false,
          _gw_route: 'error',
          error: {
            code: 'INVALID_TRANSITION',
            message: "lifecycle_status transition not allowed: '" + (currentLifecycle ?? 'NULL') + "' \u2192 '" + requestedLifecycle + "'",
            details: {
              field: 'lifecycle_status',
              from_status: currentLifecycle,
              to_status: requestedLifecycle,
              artifact_type: 'twig',
              artifact_id: existing.artifact_id,
              allowed_from_current: allowed,
              hint: "Allowed from '" + (currentLifecycle ?? 'NULL') + "': " + (allowed.length > 0 ? allowed.join(', ') : '(none -- terminal state)') + '.',
            },
          },
        },
      },
    ];
  }

  // No-op detection
  if (currentLifecycle === requestedLifecycle) {
    return [{
      json: {
        ok: true,
        _gw_route: 'ok',
        _update_mode: 'noop',
        gw_action: normalizeNode.gw_action ?? 'artifact.update',
        gw_workspace_id: normalizeNode.gw_workspace_id ?? null,
        artifact_id: existing.artifact_id,
        workspace_id: existing.workspace_id,
        artifact_type: artifact_type,
        lifecycle_status: currentLifecycle,
        version: existing.version,
      }
    }];
  }
}

// 2b. Spine only (T140: content_update also routes here)
if ((hasSpineFields || hasContent) && !hasTags && !hasExtension && !hasContentAppend) {
  // T87 Task 3: tree title freeze check
  const titleFreeze = checkTreeTitleFreeze();
  if (titleFreeze) return [{ json: titleFreeze }];

  return [
    {
      json: {
        ok: true,
        _gw_route: "ok",
        _update_mode: "spine_only",
        gw_action: normalizeNode.gw_action ?? "artifact.update",
        gw_workspace_id: normalizeNode.gw_workspace_id ?? null,
        artifact_id: existing.artifact_id,
        workspace_id: existing.workspace_id,
        artifact_type: artifact_type,
        _normalized_request: normalizeNode,
        _existing_artifact: existing,
        _gw_debug: {
          ...(normalizeNode._gw_debug ?? {}),
          mutability: "spine_only",
          operation: "UPDATE",
          spine_field_keys: spineFieldKeys,
        },
      },
    },
  ];
}

// 2c. Mixed -- tags + spine fields, no extension (single atomic PATCH)
// T140: content can combine with tags and/or spine fields
if (hasTags && (hasSpineFields || hasContent) && !hasExtension && !hasContentAppend) {
  // T87 Task 3: tree title freeze check
  const titleFreeze = checkTreeTitleFreeze();
  if (titleFreeze) return [{ json: titleFreeze }];

  return [
    {
      json: {
        ok: true,
        _gw_route: "ok",
        _update_mode: "mixed",
        gw_action: normalizeNode.gw_action ?? "artifact.update",
        gw_workspace_id: normalizeNode.gw_workspace_id ?? null,
        artifact_id: existing.artifact_id,
        workspace_id: existing.workspace_id,
        artifact_type: artifact_type,
        _normalized_request: normalizeNode,
        _existing_artifact: existing,
        _gw_debug: {
          ...(normalizeNode._gw_debug ?? {}),
          mutability: "mixed_tags_spine",
          operation: "UPDATE",
          spine_field_keys: spineFieldKeys,
        },
      },
    },
  ];
}

// --- Below: extension-only paths ---

