  const requestedStatus = execStatus ?? null;
  if (currentStatus === requestedStatus) {
    return [{
      json: {
        ok: true,
        _gw_route: 'ok',
        _update_mode: 'noop',
        gw_action: normalizeNode.gw_action ?? 'artifact.update',
        gw_workspace_id: normalizeNode.gw_workspace_id ?? null,
