  // 6.7.7 NULL reset prohibition: cannot set back to NULL once initialized
  if (currentStatus !== null && requestedStatus === null) {
    return [{
      json: {
        ok: false,
        _gw_route: 'error',
        error: {
          code: 'INVALID_TRANSITION',
          message: 'Cannot reset execution_status to NULL once initialized',
